import React, { useState } from 'react';
import { sendMessage } from '../api';

function getLatestMoodForChatbot() {
  try {
    const raw = localStorage.getItem('moodHistory');
    if (!raw) return null;
    const history = JSON.parse(raw);
    if (!Array.isArray(history) || history.length === 0) return null;
    const latest = history[0];
    return latest?.mood || null;
  } catch (e) {
    return null;
  }
}

export default function Chatbot(){
  const [msg, setMsg] = useState('');
  const [log, setLog] = useState([]);
  const send = async ()=>{
    if(!msg.trim()) return;
    const moodContext = getLatestMoodForChatbot();
    setLog(l=>[...l, {from:'me', text:msg}]);
    const r = await sendMessage(msg, moodContext);
    const botText = r.moodText ? `${r.text}\n\n${r.moodText}` : r.text;
    setLog(l=>[...l, {from:'bot', text:botText}]);
    setMsg('');
    if(r.urgent) alert('System flagged urgent — please use Emergency button or contact counselor.');
  };
  return (
    <div style={{padding:20}}>
      <h2>AI Chatbot</h2>
      <div className="chatbox">
        {log.map((m,i)=>(<div key={i} className={m.from==='me'?'msg me':'msg bot'}>{m.text}</div>))}
      </div>
      <input value={msg} onChange={e=>setMsg(e.target.value)} placeholder="Type here..." />
      <button onClick={send}>Send</button>
      <div style={{marginTop:12}}>
        <button onClick={()=>window.location.href='/therapy'}>Connect to Counselor</button>
        <button style={{marginLeft:8}} onClick={async ()=>{ const e = await (await fetch('http://localhost:4000/api/emergency/help')).json(); alert(JSON.stringify(e,null,2)) }}>Emergency</button>
      </div>
    </div>
  );
}
